import random

def get_subset_from_dimensions(dimensions, intervals=None):
    if intervals is None:
        intervals = []
        for d in dimensions:
            start = random.randint(0, d - 1)
            end = random.randint(start + 1, d)
            intervals.extend([start, end])

    def build_nd(dims, offset=0):
        if not dims:
            return offset
        if len(dims) == 1:
            return list(range(offset, offset + dims[0]))
        stride = 1
        for d in dims[1:]:
            stride *= d
        return [build_nd(dims[1:], offset + i * stride) for i in range(dims[0])]

    def extract_nd(arr, inters):
        if not inters:
            return arr
        chunk = arr[inters[0]:inters[1]]
        if len(inters) > 2:
            return [extract_nd(sub, inters[2:]) for sub in chunk]
        return chunk

    original_array = build_nd(dimensions)
    return extract_nd(original_array, intervals)
