import requests

def archive_and_list_urls(url):
    """
    Archives a URL using the Wayback Machine and returns a list of all
    archived snapshots for that URL.
    """
    headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36"
    }

    # Trigger the archival process (Save Page Now)
    save_url = f"https://web.archive.org/save/{url}"
    try:
        requests.post(save_url, headers=headers, timeout=30)
    except requests.exceptions.RequestException:
        pass

    # Retrieve the list of all snapshots from the CDX API
    cdx_url = f"https://web.archive.org/cdx/search/cdx?url={url}&output=json"
    archived_urls = []

    try:
        response = requests.get(cdx_url, headers=headers, timeout=30)
        if response.status_code == 200:
            data = response.json()
            # The first element is the header row, skip it
            if len(data) > 1:
                for row in data[1:]:
                    timestamp = row[1]
                    original_url = row[2]
                    archived_urls.append(f"https://web.archive.org/web/{timestamp}/{original_url}")
    except (requests.exceptions.RequestException, ValueError, IndexError):
        pass

    return archived_urls
