CREATE OR REPLACE FUNCTION manage_data_routine() RETURNS VOID AS $$
DECLARE
    item_val TEXT;
    data_cursor CURSOR FOR SELECT 'Standard Row 1' UNION SELECT 'Standard Row 2';
BEGIN
    -- Create the table
    CREATE TABLE temp_process_table (
        id SERIAL PRIMARY KEY,
        val TEXT
    );

    -- Open the cursor and iterate through data to insert
    OPEN data_cursor;
    LOOP
        FETCH data_cursor INTO item_val;
        EXIT WHEN NOT FOUND;
        INSERT INTO temp_process_table (val) VALUES (item_val);
    END LOOP;
    CLOSE data_cursor;

    -- Drop the table
    DROP TABLE temp_process_table;
END;
$$ LANGUAGE plpgsql;
