import os
import time
import signal
import platform
import subprocess

def terminate_process_gracefully(pid, initial_sleep=0.1, max_sleep=2.0, factor=2.0, timeout=10.0):
    """
    Terminates a process by PID gracefully with an exponential backoff timeout mechanism.
    Returns 0 on success, -1 if the process was not running, and -2 on timeout failure.
    """
    def is_running(p):
        if platform.system() == "Windows":
            try:
                output = subprocess.check_output(['tasklist', '/FI', f'PID eq {p}'], 
                                                 stderr=subprocess.STDOUT, text=True)
                return str(p) in output
            except (subprocess.CalledProcessError, FileNotFoundError):
                return False
        else:
            try:
                os.kill(p, 0)
                return True
            except (ProcessLookupError, OSError):
                return False

    # Check if the process is already gone or doesn't exist
    if not is_running(pid):
        return -1

    start_time = time.time()
    current_sleep = initial_sleep

    while (time.time() - start_time) < timeout:
        # Check if process has already terminated/failed before attempting
        if not is_running(pid):
            return 0

        try:
            if platform.system() == "Windows":
                # taskkill without /F sends a WM_CLOSE message (graceful)
                subprocess.run(['taskkill', '/PID', str(pid)], 
                               stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            else:
                os.kill(pid, signal.SIGTERM)
        except (ProcessLookupError, OSError):
            if not is_running(pid):
                return 0

        # Wait with exponential backoff
        time.sleep(current_sleep)
        current_sleep = min(current_sleep * factor, max_sleep)

    return 0 if not is_running(pid) else -2
