import re
import json
from collections import Counter

def extract_text_from_pdf(pdf_path):
    try:
        # Uses 'pdftotext' (part of Poppler/Xpdf) to extract text to stdout
        process = subprocess.run(['pdftotext', pdf_path, '-'], 
                                capture_output=True, 
                                text=True, 
                                check=True)
        return process.stdout
    except subprocess.CalledProcessError as e:
        print(f"Error extracting text: {e}")
        return ""
    except FileNotFoundError:
        print("Error: 'pdftotext' command not found. Please install Poppler.")
        return ""

def tokenize(text):
    # Convert to lowercase and find all alphanumeric words
    words = re.findall(r'\b\w+\b', text.lower())
    return words

def create_bag_of_words(tokens):
    return dict(Counter(tokens))

def save_bow_to_json(bow, output_path):
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(bow, f, indent=4)

def process_pdf_to_bow(input_pdf, output_file):
    text = extract_text_from_pdf(input_pdf)
    if not text:
        return

    tokens = tokenize(text)
    bow = create_bag_of_words(tokens)
    save_bow_to_json(bow, output_file)

