import shelve

def data_filter_service(storage_file, mode='record', data_stream=None, filter_types=None):
    """
    Manages recording and playback of data filtered by type using shelve.

    :param storage_file: Path to the shelve database file.
    :param mode: 'record' to save data, 'playback' to retrieve data.
    :param data_stream: Iterable of data items to filter and record.
    :param filter_types: List of types (e.g., [int, str]) to include.
    :return: Dictionary of data if mode is 'playback', else None.
    """
    if filter_types is None:
        filter_types = []

    output = None

    with shelve.open(storage_file, writeback=True) as db:
        if mode == 'record' and data_stream is not None:
            for item in data_stream:
                # Check if item matches any of the requested types
                if any(isinstance(item, t) for t in filter_types):
                    type_key = type(item).__name__
                    if type_key not in db:
                        db[type_key] = []

                    # Update the list for the specific type
                    temp_list = db[type_key]
                    temp_list.append(item)
                    db[type_key] = temp_list

        elif mode == 'playback':
            if not filter_types:
                # Return everything stored if no specific types provided
                output = {k: v for k, v in db.items()}
            else:
                # Return only data matching the specified types
                output = {
                    t.__name__: db.get(t.__name__, []) 
                    for t in filter_types
                }

    return output
