RETURNS INTEGER AS $$
DECLARE
    affected_count INTEGER := 0;
    lock_id_val BIGINT := hashtext(lock_key_name);
BEGIN
    CREATE TEMP TABLE IF NOT EXISTS target_data (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) UNIQUE
    );

