        affected_count := affected_count + 1;
    EXCEPTION WHEN OTHERS THEN
        PERFORM pg_advisory_unlock(lock_id_val);
        RAISE EXCEPTION 'OperationalError: %', SQLERRM;
    END;

    PERFORM pg_advisory_unlock(lock_id_val);
    RETURN affected_count;
END;
