class FileSystemTester:
    def __init__(self, directory="."):
        self.directory = directory

    def run_tests(self, filename="test_file.txt", content="Hello, World!"):
        filepath = os.path.join(self.directory, filename)

        try:
            # 1. Create and Write to a file
            with open(filepath, 'w') as f:
                f.write(content)

            # 2. Read from the file
            with open(filepath, 'r') as f:
                data = f.read()
                if data != content:
                    raise IOError("Data integrity check failed.")

            # 3. Raise an intentional exception
            if os.path.exists(filepath):
                raise RuntimeError("Intentional exception after successful file check.")

        except RuntimeError as e:
            print(f"Caught expected exception: {e}")

            # 4. Pickle the file system object (self)
            pickled_data = pickle.dumps(self)
            restored_obj = pickle.loads(pickled_data)

            # Cleanup
            if os.path.exists(filepath):
                os.remove(filepath)

            return {
                "status": "Success",
                "read_data": data,
                "pickled_size": len(pickled_data),
                "restored_directory": restored_obj.directory
            }
        except Exception as e:
            if os.path.exists(filepath):
                os.remove(filepath)
            raise e

def test_fs_operations():
