def initialize_config(file_path=None):
    """
    Populates _CONFIG_DATA from command-line arguments and an optional JSON file.
    Internal schema: { key: {"value": val, "source": src} }
    """
    global _CONFIG_DATA
    parser = argparse.ArgumentParser()
    parser.add_argument("--database_url", help="Database connection string")
    parser.add_argument("--port", type=int, help="Server port")
    args, unknown = parser.parse_known_args()

    # 1. Load from file
    if file_path:
        try:
            with open(file_path, 'r') as f:
                file_data = json.load(f)
                for k, v in file_data.items():
                    _CONFIG_DATA[k] = {"value": v, "source": "config_file"}
        except (FileNotFoundError, json.JSONDecodeError):
            pass

    # 2. Overwrite with CLI arguments (highest priority)
    for key, value in vars(args).items():
        if value is not None:
            _CONFIG_DATA[key] = {"value": value, "source": "command_line"}

def get_config_value(config_name):
    """
    Retrieves a config value, logs metadata, and broadcasts to handlers.
    """
    item = _CONFIG_DATA.get(config_name)

    if item is None:
        logging.warning(f"Configuration key '{config_name}' not found.")
        return None

