import sqlite3

def get_table_row_counts(db_path, table_names):
    if not table_names:
        return {}

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    row_counts = {}
    reference_schema = None

    try:
        for table in table_names:
            # Retrieve schema information
            # PRAGMA table_info returns (id, name, type, notnull, default_value, pk)
            cursor.execute(f"PRAGMA table_info({table})")
            current_schema = cursor.fetchall()

            if not current_schema:
                raise ValueError(f"Table '{table}' does not exist.")

            # Validate schema consistency
            if reference_schema is None:
                reference_schema = current_schema
            elif current_schema != reference_schema:
                raise ValueError(f"Table '{table}' has a different schema than the others.")

            # Retrieve row count
            cursor.execute(f"SELECT COUNT(*) FROM {table}")
            count = cursor.fetchone()[0]

            if count == 0:
                raise ValueError(f"Table '{table}' has zero rows.")

            row_counts[table] = count
    finally:
        conn.close()

    return row_counts
