import os

def extract_information(filename):
    """
    Reads a text file and extracts information grouped by blank lines.
    Returns a list of lists, where each sublist is a group of lines.
    """
    extracted_data = []
    current_group = []

    try:
        # Check if the file exists before attempting to open
        if not os.path.exists(filename):
            raise FileNotFoundError(f"The file '{filename}' does not exist.")

        with open(filename, 'r', encoding='utf-8') as file:
            for line in file:
                # Remove leading/trailing whitespace
                clean_line = line.strip()

                if clean_line:
                    # If line has content, add to current group
                    current_group.append(clean_line)
                else:
                    # If line is empty and we have a current group, save it
                    if current_group:
                        extracted_data.append(current_group)
                        current_group = []

            # Handle the final group if the file doesn't end with a blank line
            if current_group:
                extracted_data.append(current_group)

    except FileNotFoundError as e:
        print(f"Error: {e}")
    except PermissionError:
        print(f"Error: Permission denied when accessing '{filename}'.")
    except UnicodeDecodeError:
        print(f"Error: The file '{filename}' contains invalid characters and cannot be read as text.")
    except Exception as e:
        print(f"An unexpected error occurred while processing the file: {e}")

    return extracted_data
