from functools import update_wrapper

def create_updated_function(new_definitions, original_func):
    class UpdatedFunction:
        def __init__(self, defs, func):
            # Copy original function metadata like __name__, __doc__, __module__
            update_wrapper(self, func)
            self.defs = defs
            self.func = func

        def __call__(self, *args, **kwargs):
            # Combine the stored definitions with the provided keyword arguments
            # Parameters provided during the call override the stored definitions
            combined_kwargs = {**self.defs, **kwargs}
            return self.func(*args, **combined_kwargs)

        def __repr__(self):
            # Custom string representation
            return f"Updated function '{self.__name__}' with definitions: {self.defs}"

    return UpdatedFunction(new_definitions, original_func)
