import json
import os

class InputIterator:
    def __init__(self, path, fail_on_missing=True):
        """
        Initializes the iterator.
        :param path: Local file path or bucket URI (e.g., s3://bucket/key).
        :param fail_on_missing: Boolean to determine if missing input raises an error.
        """
        self.path = path
        self.fail_on_missing = fail_on_missing

    def __iter__(self):
        try:
            # We attempt to use smart_open to handle bucket URIs transparently.
            # If smart_open is not installed, we fallback to standard open for local files.
            try:
                from smart_open import open as open_func
            except ImportError:
                if not os.path.exists(self.path) and self.fail_on_missing:
                    raise FileNotFoundError(f"Path {self.path} does not exist.")
                open_func = open

            with open_func(self.path, 'r') as f:
                for line in f:
                    yield line
        except Exception as e:
            if self.fail_on_missing:
                raise e

    def to_json(self) -> str:
        """Serializes the object to a JSON string."""
        return json.dumps({
            "path": self.path,
            "fail_on_missing": self.fail_on_missing
        })

    @classmethod
    def from_json(cls, json_str: str):
        """Creates an instance of the class from a JSON string."""
        data = json.loads(json_str)
        return cls(
            path=data.get("path"),
            fail_on_missing=data.get("fail_on_missing", True)
        )
