import requests
from flask import Flask, request, redirect, url_for, session

app = Flask(__name__)
app.secret_key = 'paypal_integration_secret_key'

PAYPAL_API_BASE = "https://api-m.sandbox.paypal.com"

FORM_TEMPLATE = """
<!DOCTYPE html>
<html>
<head><title>PayPal Payment</title></head>
<body>
    <h2>Checkout</h2>
    <form method="POST" action="/pay">
        <p>PayPal Client ID: <input type="text" name="client_id" required></p>
        <p>PayPal Client Secret: <input type="password" name="client_secret" required></p>
        <p>Amount: <input type="number" step="0.01" name="amount" value="10.00" required></p>
        <button type="submit">Pay with PayPal</button>
    </form>
</body>
</html>
"""

def get_access_token(client_id, client_secret):
    url = f"{PAYPAL_API_BASE}/v1/oauth2/token"
    headers = {"Accept": "application/json", "Accept-Language": "en_US"}
    data = {"grant_type": "client_credentials"}
    response = requests.post(url, auth=(client_id, client_secret), headers=headers, data=data)
    return response.json().get('access_token')

@app.route('/')
def index():
    return FORM_TEMPLATE

@app.route('/pay', methods=['POST'])
def pay():
    client_id = request.form['client_id']
    client_secret = request.form['client_secret']
    amount = request.form['amount']

    # Store credentials in session for use in the callback
    session['client_id'] = client_id
    session['client_secret'] = client_secret

    token = get_access_token(client_id, client_secret)
    if not token:
        return "Authentication failed. Check your Client ID and Secret."

    payment_payload = {
        "intent": "sale",
        "payer": {"payment_method": "paypal"},
        "redirect_urls": {
            "return_url": url_for('success', _external=True),
            "cancel_url": url_for('cancel', _external=True)
        },
        "transactions": [{
            "amount": {"total": amount, "currency": "USD"},
            "description": "Flask App Payment"
        }]
    }

    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {token}"
    }

    response = requests.post(f"{PAYPAL_API_BASE}/v1/payments/payment", json=payment_payload, headers=headers)
    payment_data = response.json()

    if response.status_code != 201:
        return f"Payment creation failed: {payment_data.get('message')}"

    for link in payment_data.get('links', []):
        if link['rel'] == 'approval_url':
            return redirect(link['href'])

    return "No approval URL found."

@app.route('/success')
def success():
    payment_id = request.args.get('paymentId')
    payer_id = request.args.get('PayerID')

    client_id = session.get('client_id')
    client_secret = session.get('client_secret')

    if not payment_id or not payer_id:
        return "Invalid payment callback data."

    token = get_access_token(client_id, client_secret)
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {token}"
    }

    # Execute the payment
    execute_url = f"{PAYPAL_API_BASE}/v1/payments/payment/{payment_id}/execute"
    response = requests.post(execute_url, json={"payer_id": payer_id}, headers=headers)
    result = response.json()

    if response.status_code == 200:
        return f"<h1>Payment Success!</h1><p>Payment ID: {payment_id}</p><p>Status: {result.get('state')}</p>"
    else:
        return f"<h1>Payment Execution Failed</h1><p>{result.get('message')}</p>"

@app.route('/cancel')
def cancel():
    return "<h1>Payment Cancelled</h1><p>The user cancelled the transaction.</p><a href='/'>Go Back</a>"

if __name__ == '__main__':
    app.run(debug=True)
