import re

def extract_files_from_text(file_path):
    # Regex pattern to match 'name-version.tar.gz'
    # [a-zA-Z0-9_-]+ matches the pattern/name
    # [\d\.]+ matches the version (digits and dots)
    # \.tar\.gz matches the literal extension
    file_regex = r'[a-zA-Z0-9_-]+-[\d\.]+\.tar\.gz'

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            content = f.read()
            matches = re.findall(file_regex, content)
            return matches
    except FileNotFoundError:
        return "Error: The file was not found."
