using System.IO;
using System.Linq;
using System.Reflection;
using System.Collections.Generic;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.Emit;

public class DynamicExecutionManager
{
    public static void Main(string[] args)
    {
        // Example dynamic payload source code
        string sourceCode = @"
using System;
namespace DynamicPayload
{
    public class Program
    {
        public static void Main(string[] args)
        {
            Console.WriteLine(""[+] Dynamic payload started."");
            Console.WriteLine(""[+] Received arguments: "" + string.Join("" "", args));
        }
    }
}";

        CompileAndExecute(sourceCode, args);
    }

    public static void CompileAndExecute(string sourceCode, string[] args)
    {
        // Parse the source code into a syntax tree
        SyntaxTree syntaxTree = CSharpSyntaxTree.ParseText(sourceCode);

        // Generate a random name for the assembly
        string assemblyName = Path.GetRandomFileName();

        // Collect references from the current execution context
        // This ensures the compiled code has access to standard libraries
        var references = AppDomain.CurrentDomain.GetAssemblies()
            .Where(a => !a.IsDynamic && !string.IsNullOrWhiteSpace(a.Location))
            .Select(a => MetadataReference.CreateFromFile(a.Location))
            .Cast<MetadataReference>()
            .ToList();

        // Create the compilation object
        CSharpCompilation compilation = CSharpCompilation.Create(
            assemblyName,
            syntaxTrees: new[] { syntaxTree },
            references: references,
            options: new CSharpCompilationOptions(OutputKind.ConsoleApplication)
                .WithOptimizationLevel(OptimizationLevel.Release));

        using (var ms = new MemoryStream())
        {
            // Emit the compilation to an in-memory stream
            EmitResult result = compilation.Emit(ms);

            if (!result.Success)
            {
                Console.WriteLine("[-] Compilation failed:");
                foreach (Diagnostic diagnostic in result.Diagnostics)
                {
                    Console.WriteLine($"\t{diagnostic.ToString()}");
                }
                return;
            }

            // Load the compiled assembly from the stream
            ms.Seek(0, SeekOrigin.Begin);
            byte[] assemblyBytes = ms.ToArray();
            Assembly assembly = Assembly.Load(assemblyBytes);

            // Locate the Entry Point (Main method) and invoke it
            MethodInfo entryPoint = assembly.EntryPoint;
            if (entryPoint != null)
            {
                // Passing the command line arguments to the dynamic Main method
                entryPoint.Invoke(null, new object[] { args });
            }
            else
            {
                Console.WriteLine("[-] No EntryPoint found in compiled assembly.");
            }
        }
    }
}
