import json
import ast

def deserialize_json(json_string, decode_keys=False):
    """
    Deserializes a JSON string into a Python object, optionally decoding
    stringified dictionary keys back into their Python literal types.
    """
    if not decode_keys:
        return json.loads(json_string)

    def object_pairs_hook(pairs):
        decoded_dict = {}
        for key, value in pairs:
            try:
                # Attempt to evaluate string keys as Python literals (e.g., int, tuple, bool)
                new_key = ast.literal_eval(key)
            except (ValueError, SyntaxError):
                new_key = key
            decoded_dict[new_key] = value
        return decoded_dict

    return json.loads(json_string, object_pairs_hook=object_pairs_hook)
