import sys

def reraise_with_context(exc, message):
    """Custom function to re-raise exceptions with additional context."""
    raise type(exc)(f"{message}: {str(exc)}") from exc

def handle_version_specific_logic():
    # Handle conditional imports based on Python version
    try:
        if sys.version_info >= (3, 11):
            # tomllib is built-in for 3.11+
            import tomllib as toml_provider
        else:
            # Fallback for older versions
            import tomli as toml_provider
    except ImportError as e:
        reraise_with_context(e, "Failed to load a TOML parser for this Python version")

    # Handle feature-specific availability (e.g., zoneinfo vs pytz)
    try:
        if sys.version_info >= (3, 9):
            from zoneinfo import ZoneInfo
        else:
            from backports.zoneinfo import ZoneInfo
    except ImportError as e:
        reraise_with_context(e, "Required timezone library is missing")

    return toml_provider, ZoneInfo

