import yaml

def update_yaml_config(file_path, updates):
    """
    Loads a YAML file, applies updates from a dictionary, and saves it back.

    :param file_path: Path to the YAML configuration file.
    :param updates: Dictionary containing the keys and values to update.
    """
    try:
        # Load existing configuration
        with open(file_path, 'r') as file:
            config = yaml.safe_load(file) or {}

        # Modify the contents
        if isinstance(config, dict):
            config.update(updates)
        else:
            raise ValueError("YAML root must be a dictionary to update with the provided data.")

        # Save back to disk
        with open(file_path, 'w') as file:
            yaml.safe_dump(config, file, default_flow_style=False)

    except FileNotFoundError:
        print(f"Error: The file '{file_path}' does not exist.")
    except yaml.YAMLError as e:
        print(f"Error parsing YAML data: {e}")
    except PermissionError:
        print(f"Error: Permission denied when writing to '{file_path}'.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
