import hashlib

def get_cryptographic_hash(strings, hash_algorithm, unit='hex'):
    """
    Computes the cryptographic hash of a list of strings in the order provided.

    :param strings: List of strings to hash.
    :param hash_algorithm: String name of the hash algorithm (e.g., 'sha256', 'md5').
    :param unit: Format of the output ('hex' for hexadecimal string, 'bytes' for raw bytes).
    :return: The computed hash in the specified unit.
    """
    try:
        hasher = hashlib.new(hash_algorithm)
    except ValueError:
        raise ValueError(f"Unsupported hash algorithm: {hash_algorithm}")

    for s in strings:
        hasher.update(s.encode('utf-8'))

    if unit == 'hex':
        return hasher.hexdigest()
    elif unit == 'bytes':
        return hasher.digest()
    else:
        raise ValueError(f"Invalid unit: {unit}. Supported units are 'hex' and 'bytes'.")
