import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java AntlrRunner <directory> <grammar-file> [options...]");
            return;
        }

        String directoryPath = args[0];
        String grammarFile = args[1];
        String[] options = Arrays.copyOfRange(args, 2, args.length);

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("org.antlr.v4.Tool");
        command.addAll(Arrays.asList(options));
        command.add(grammarFile);

        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.directory(new File(directoryPath));
        processBuilder.redirectErrorStream(true);

        try {
            Process process = processBuilder.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("ANTLR tool encountered an error. Exit code: " + exitCode);
            } else {
                System.out.println("ANTLR tool completed successfully.");
            }
        } catch (IOException e) {
            System.err.println("Error starting the process: " + e.getMessage());
        } catch (InterruptedException e) {
            System.err.println("Process was interrupted: " + e.getMessage());
            Thread.currentThread().interrupt();
        }
    }
}

